examples.original_ir:
define i32 @test(i1 %c, i32 %v) {
entry:
  %x = add nsw i32 %v, 1
  br i1 %c, label %if.then, label %if.end

if.then:
  br label %if.end

if.end:
  %phi = phi i32 [ %x, %if.then ], [ undef, %entry ]
  ret i32 %phi
}

examples.optimized_ir:
define i32 @test(i1 %c, i32 %v) {
entry:
  %x = add nsw i32 %v, 1
  ret i32 %x
}
